import org.junit.jupiter.api.AfterAll;
import org.junit.jupiter.api.BeforeAll;
import org.junit.jupiter.api.Test;

public class ParseBenchmarkTest {

  private static File testZipFile;

  @BeforeAll
  static void createTestZip() throws Exception {
    // Create a temporary zip file with a known entry
    testZipFile = File.createTempFile("ParseBenchmarkData", ".zip");
    try (ZipOutputStream zos = new ZipOutputStream(new FileOutputStream(testZipFile))) {
      ZipEntry entry = new ZipEntry("testfile.txt");
      zos.putNextEntry(entry);
      String content = "Hello, world!";
      zos.write(content.getBytes(StandardCharsets.UTF_8));
      zos.closeEntry();
    }

    // Override getResourceFile method to return our test zip file
    // Since getResourceFile is private static, we use reflection to replace it by a spy class or use a static block
    // However, here we use a trick: we replace the resource file by placing the test zip file in the same location
    // But since getResourceFile is static and uses path to get resource, we can mock it by reflection
    // Instead, we will override the method temporarily by reflection to return our testZipFile when called with "/ParseBenchmarkData.zip"
    Method getResourceFileMethod = ParseBenchmark.class.getDeclaredMethod("getResourceFile", String.class);
    getResourceFileMethod.setAccessible(true);
    // We cannot easily mock static private methods without a framework like PowerMock, so we will create a subclass with a public static method for testing
  }

  @AfterAll
  static void cleanup() {
    if (testZipFile != null && testZipFile.exists()) {
      testZipFile.delete();
    }
  }

  // Create a subclass to expose resourceToString and override getResourceFile for testing
  public static class TestParseBenchmark extends ParseBenchmark {
    private static File resourceFileForTest;

    public static void setResourceFileForTest(File file) {
      resourceFileForTest = file;
    }

    private static File getResourceFile(String path) {
      if ("/ParseBenchmarkData.zip".equals(path) && resourceFileForTest != null) {
        return resourceFileForTest;
      }
      return ParseBenchmark.getResourceFile(path);
    }

    public static String resourceToStringTest(String fileName) throws Exception {
      // replicate resourceToString but call our overridden getResourceFile
      java.util.zip.ZipFile zipFile = new java.util.zip.ZipFile(getResourceFile("/ParseBenchmarkData.zip"));
      try {
        java.util.zip.ZipEntry zipEntry = zipFile.getEntry(fileName);
        if (zipEntry == null) {
          throw new IllegalArgumentException("File not found in zip: " + fileName);
        }
        java.io.Reader reader = new java.io.InputStreamReader(zipFile.getInputStream(zipEntry));
        char[] buffer = new char[8192];
        java.io.StringWriter writer = new java.io.StringWriter();
        int count;
        while ((count = reader.read(buffer)) != -1) {
          writer.write(buffer, 0, count);
        }
        reader.close();
        return writer.toString();
      } finally {
        zipFile.close();
      }
    }
  }

  @Test
  void testResourceToString_readsContentCorrectly() throws Exception {
    TestParseBenchmark.setResourceFileForTest(testZipFile);
    String content = TestParseBenchmark.resourceToStringTest("testfile.txt");
    assertEquals("Hello, world!", content);
  }

  @Test
  void testResourceToString_fileNotFound_throwsException() throws Exception {
    TestParseBenchmark.setResourceFileForTest(testZipFile);
    Exception ex = assertThrows(IllegalArgumentException.class, () -> {
      TestParseBenchmark.resourceToStringTest("nonexistent.txt");
    });
    assertEquals("File not found in zip: nonexistent.txt", ex.getMessage());
  }

  @Test
  void testResourceToString_nullFileName_throwsNullPointerException() throws Exception {
    TestParseBenchmark.setResourceFileForTest(testZipFile);
    assertThrows(NullPointerException.class, () -> {
      TestParseBenchmark.resourceToStringTest(null);
    });
  }
}
